// Normalize Spec Input
// Transforms raw webhook payload into a consistent internal structure.
// Handles missing fields, trims text, computes word counts, detects sections.

const body = $('Webhook').item.json.body || $('Webhook').item.json;

const userId = body.user_id || 'anonymous';
const analysisMode = body.analysis_mode || 'single_spec';
const preferredTone = body.preferred_tone || 'direct';
const timeWindowStart = body.time_window_start || null;
const timeWindowEnd = body.time_window_end || null;
const rawSpecs = Array.isArray(body.specs) ? body.specs : [];

if (rawSpecs.length === 0) {
  throw new Error('No specs provided in payload. Payload must include a non-empty specs array.');
}

const KNOWN_SECTION_KEYWORDS = [
  'overview', 'goals', 'objectives', 'requirements', 'scope', 'assumptions',
  'open questions', 'out of scope', 'edge cases', 'dependencies', 'metrics',
  'success criteria', 'acceptance criteria', 'context', 'background',
  'constraints', 'risks', 'timeline', 'stakeholders', 'glossary', 'appendix'
];

function normalizeSpec(spec, index) {
  const title = (spec.title || `Untitled Spec ${index + 1}`).trim();
  const type = (spec.type || 'unknown').toLowerCase().trim();
  const rawText = (spec.raw_text || '').trim();
  const sections = Array.isArray(spec.sections) ? spec.sections.map(s => s.toLowerCase().trim()) : [];

  const wordCount = rawText.split(/\s+/).filter(w => w.length > 0).length;
  const sentences = rawText.split(/[.!?]+/).filter(s => s.trim().length > 0);
  const paragraphs = rawText.split(/\n\n+/).filter(p => p.trim().length > 0);

  const detectedSections = KNOWN_SECTION_KEYWORDS.filter(keyword =>
    rawText.toLowerCase().includes(keyword) || sections.includes(keyword)
  );

  return {
    _debug_normalized: true,
    _debug_spec_index: index,
    title,
    type,
    raw_text: rawText,
    sections,
    _debug_word_count: wordCount,
    _debug_sentence_count: sentences.length,
    _debug_paragraph_count: paragraphs.length,
    _debug_detected_sections: detectedSections,
    _debug_section_count: detectedSections.length
  };
}

const normalizedSpecs = rawSpecs.map(normalizeSpec);

return {
  user_id: userId,
  analysis_mode: analysisMode,
  preferred_tone: preferredTone,
  time_window_start: timeWindowStart,
  time_window_end: timeWindowEnd,
  normalized_specs: normalizedSpecs,
  _debug_spec_count: normalizedSpecs.length,
  _debug_normalization_complete: true,
  // Carry forward provider config
  _debug_provider_endpoint: $('Provider Config').item.json._debug_provider_endpoint,
  _debug_model_name: $('Provider Config').item.json._debug_model_name,
  _debug_max_tokens: $('Provider Config').item.json._debug_max_tokens,
  _debug_temperature: $('Provider Config').item.json._debug_temperature,
  _debug_retry_max_attempts: $('Provider Config').item.json._debug_retry_max_attempts,
  _debug_provider_type: $('Provider Config').item.json._debug_provider_type
};

// Extract Structural Signals
// Scans normalized text for structural signals that inform ambiguity detection
// without requiring AI. Detects section presence, ownership signals, dependency
// references, acceptance criteria signals, and document complexity proxies.

const data = $input.item.json;
const specs = data.normalized_specs;

const OUT_OF_SCOPE_PATTERNS = [
  /out.of.scope/i, /not in scope/i, /excluded/i, /deferred/i,
  /not included/i, /won.t include/i, /will not include/i
];

const OPEN_QUESTIONS_PATTERNS = [
  /open.question/i, /tbd/i, /to be determined/i, /to be decided/i,
  /unresolved/i, /pending decision/i, /needs clarification/i
];

const ASSUMPTIONS_PATTERNS = [
  /assumption/i, /we assume/i, /assuming/i, /it is assumed/i, /presumes/i
];

const OWNERSHIP_PATTERNS = [
  /owned by/i, /responsible for/i, /assigned to/i, /lead[s]? by/i,
  /[A-Z][a-z]+ team will/i, /[A-Z][a-z]+ squad/i, /[A-Z][a-z]+ will own/i
];

const ACCEPTANCE_CRITERIA_PATTERNS = [
  /acceptance criteria/i, /definition of done/i, /success metric/i,
  /must achieve/i, /kpi/i, /measur/i, /verif/i, /< \d+/, />\s*\d+\s*ms/i,
  /\d+%/, /p\d{2}/i, /latency/i, /threshold/i
];

const DEPENDENCY_PATTERNS = [
  /api/i, /third.party/i, /external service/i, /depends on/i,
  /requires/i, /legal review/i, /design assets/i, /analytics/i,
  /stakeholder approval/i, /integration with/i
];

function extractSignals(spec) {
  const text = spec.raw_text;
  const lowerText = text.toLowerCase();

  const hasOutOfScope = OUT_OF_SCOPE_PATTERNS.some(p => p.test(text));
  const hasOpenQuestions = OPEN_QUESTIONS_PATTERNS.some(p => p.test(text));
  const hasAssumptions = ASSUMPTIONS_PATTERNS.some(p => p.test(text));
  const hasOwnershipSignals = OWNERSHIP_PATTERNS.some(p => p.test(text));
  const hasAcceptanceCriteriaSignals = ACCEPTANCE_CRITERIA_PATTERNS.some(p => p.test(text));
  const hasNamedDependencies = DEPENDENCY_PATTERNS.some(p => p.test(text));

  // Extract any text after out-of-scope markers
  const outOfScopeMatch = text.match(/(?:out.of.scope|not included|deferred)[:\s]+([^.!?\n]{10,200})/i);
  const detectedOutOfScopeItems = outOfScopeMatch ? outOfScopeMatch[1].trim() : 'none detected';

  // Extract any text after open questions markers
  const openQMatch = text.match(/(?:open.question|tbd|to be determined)[:\s]+([^.!?\n]{10,200})/i);
  const detectedOpenQuestions = openQMatch ? openQMatch[1].trim() : 'none detected';

  const sectionList = spec._debug_detected_sections.join(', ') || 'none detected';

  return {
    ...spec,
    _debug_has_out_of_scope_section: hasOutOfScope,
    _debug_has_open_questions_section: hasOpenQuestions,
    _debug_has_assumptions_section: hasAssumptions,
    _debug_has_ownership_signals: hasOwnershipSignals,
    _debug_has_acceptance_criteria_signals: hasAcceptanceCriteriaSignals,
    _debug_has_named_dependencies: hasNamedDependencies,
    _debug_detected_out_of_scope_items: detectedOutOfScopeItems,
    _debug_detected_open_questions: detectedOpenQuestions,
    _debug_structural_section_list: sectionList
  };
}

const specsWithSignals = specs.map(extractSignals);

return {
  ...data,
  normalized_specs: specsWithSignals,
  _debug_signal_extraction_complete: true
};

// Detect Deterministic Ambiguity Flags
// Rule-based, non-AI ambiguity detection. Operates entirely without AI.
// Catches high-confidence signal patterns and produces preliminary severity estimates.

const data = $input.item.json;
const specs = data.normalized_specs;

// Configurable vague term vocabulary — extend this list for your team's domain
const VAGUE_TERMS = [
  'fast', 'slow', 'easy', 'hard', 'difficult', 'simple', 'complex',
  'intuitive', 'robust', 'appropriate', 'seamless', 'support', 'handle',
  'manage', 'user-friendly', 'efficient', 'scalable', 'reliable', 'better',
  'improve', 'enhance', 'optimal', 'sufficient', 'adequate', 'reasonable',
  'significant', 'minimal', 'large', 'small', 'good', 'bad', 'nice',
  'clean', 'smooth', 'modern', 'natural', 'relevant', 'quickly', 'slowly',
  'effectively', 'properly', 'correctly', 'appropriately', 'eventually',
  'performance', 'responsive', 'dynamic', 'flexible', 'intelligent'
];

function detectVagueTerms(text) {
  const found = [];
  const lowerText = text.toLowerCase();
  for (const term of VAGUE_TERMS) {
    const regex = new RegExp(`\\b${term}\\b`, 'gi');
    if (regex.test(lowerText)) {
      found.push(term);
    }
  }
  return [...new Set(found)];
}

function detectContradictions(text) {
  const lowerText = text.toLowerCase();
  const inScopeSignals = [
    /in scope/i, /included in/i, /will include/i, /will support/i, /in this release/i
  ];
  const outScopeSignals = [
    /out of scope/i, /not included/i, /excluded/i, /deferred/i, /not in this release/i
  ];

  const hasInScope = inScopeSignals.some(p => p.test(text));
  const hasOutScope = outScopeSignals.some(p => p.test(text));

  // Basic heuristic: if both in-scope and out-of-scope signals exist for overlapping content
  if (hasInScope && hasOutScope) {
    // Check for the same noun appearing in both contexts
    const subjects = text.match(/(?:will include|in scope)[:\s]+([\w\s]{3,30})/gi) || [];
    const excluded = text.match(/(?:out of scope|excluded|deferred)[:\s]+([\w\s]{3,30})/gi) || [];
    if (subjects.length > 0 && excluded.length > 0) {
      return true;
    }
  }
  return false;
}

function estimatePreSeverity(flags, wordCount) {
  if (wordCount < 150) return 'low_signal_noise';
  const count = flags.length;
  if (count === 0) return 'none';
  if (count <= 2) return 'low';
  if (count <= 4) return 'medium';
  if (count <= 6) return 'high';
  return 'critical';
}

function detectFlagsForSpec(spec) {
  const text = spec.raw_text;
  const flags = [];

  const vagueTermsFound = detectVagueTerms(text);
  if (vagueTermsFound.length > 0) {
    flags.push({ flag_type: 'vague_language', matched_terms: vagueTermsFound, confidence: 'high' });
  }

  if (!spec._debug_has_out_of_scope_section) {
    flags.push({ flag_type: 'scope_boundary_gap', matched_terms: [], confidence: 'medium' });
  }

  if (!spec._debug_has_open_questions_section) {
    flags.push({ flag_type: 'missing_decision_point', matched_terms: [], confidence: 'low' });
  }

  if (!spec._debug_has_ownership_signals) {
    flags.push({ flag_type: 'undefined_ownership', matched_terms: [], confidence: 'medium' });
  }

  if (!spec._debug_has_acceptance_criteria_signals) {
    flags.push({ flag_type: 'missing_acceptance_criteria', matched_terms: [], confidence: 'medium' });
  }

  if (!spec._debug_has_named_dependencies && spec._debug_word_count > 200) {
    flags.push({ flag_type: 'dependency_blind_spot', matched_terms: [], confidence: 'low' });
  }

  if (detectContradictions(text)) {
    flags.push({ flag_type: 'contradictory_requirement', matched_terms: [], confidence: 'medium' });
  }

  const preSeverity = estimatePreSeverity(flags, spec._debug_word_count);

  return {
    ...spec,
    _debug_deterministic_flags: flags,
    _debug_vague_terms_found: vagueTermsFound,
    _debug_pre_severity_estimate: preSeverity,
    _debug_flag_count: flags.length
  };
}

const specsWithFlags = specs.map(detectFlagsForSpec);

// Aggregate: determine if any spec is low signal
const anyLowSignal = specsWithFlags.some(s => s._debug_pre_severity_estimate === 'low_signal_noise');
const allLowSignal = specsWithFlags.every(s => s._debug_pre_severity_estimate === 'low_signal_noise');

return {
  ...data,
  normalized_specs: specsWithFlags,
  _debug_any_low_signal: anyLowSignal,
  _debug_all_low_signal: allLowSignal,
  _debug_deterministic_detection_complete: true
};

// Prep Spec Analysis Request
// Constructs the full prompt payload for the AI analysis call.
// Merges system prompt with runtime-interpolated user prompt.
// All structural signal data is embedded as context.

const data = $input.item.json;
const spec = data.normalized_specs[0]; // Process first spec; extend for batch processing

const SYSTEM_PROMPT = `You are a requirements-quality analyst. Your sole function is to read a product specification, feature brief, PRD, user story set, or implementation document and produce a structured diagnostic identifying ambiguity patterns that could cause delivery risk if left unresolved.

You are not a writing coach. You are not a summarizer. You are not a spec generator. You diagnose the spec that was written — you do not rewrite it.

Your output must be operational. Every item you surface must be tied to specific language in the input document. You must not invent problems not evidenced by the text.

ALLOWED AMBIGUITY CATEGORIES (use exact strings only):
- vague_language: Terms without measurable criteria (fast, intuitive, robust, seamless, appropriate, support, handle)
- missing_acceptance_criteria: Requirements with no verifiable success conditions
- undefined_ownership: No named role, team, squad, or service assigned to a decision or requirement
- missing_decision_point: Feature direction without documented unresolved choices
- scope_boundary_gap: No definition of what is excluded, deferred, or out of scope
- dependency_blind_spot: Quiet reliance on external services, APIs, or approvals without naming them
- untestable_requirement: Requirements stated as intent or feeling rather than observable behavior
- contradictory_requirement: Two statements that cannot both be true
- assumption_without_validation: Unvalidated premises stated as facts
- low_signal_noise: Document too thin for meaningful analysis (use sparingly — only for genuinely insufficient documents)

SEVERITY RULES:
- none: No ambiguity detected
- low: 1-2 minor vague terms or a missing section that is low-risk
- medium: 3-4 categories, or unclear ownership in 1-2 places
- high: 5+ categories, or core requirement has no owner, no testable criteria, and conflicting scope
- critical: Contradictory requirements present, or multiple simultaneous high-severity gaps. Always sets needs_human_review: true.

CONFIDENCE RULES:
- low: Document is ambiguous enough that you cannot distinguish intentional choices from gaps
- medium: Most patterns clearly evidenced; one or two involve interpretation
- high: All patterns clearly evidenced by specific document language

RESPOND WITH A SINGLE VALID JSON OBJECT. No markdown. No code fences. No prose before or after the JSON. Required fields:
{
  "ambiguity_summary": "2-5 sentences on ambiguity patterns present and why they create delivery risk",
  "ambiguity_categories": ["array of category strings"],
  "severity_level": "none|low|medium|high|critical",
  "highest_risk_sections": ["section names"],
  "vague_terms_detected": ["exact terms from document"],
  "missing_decisions": ["specific unresolved decisions"],
  "undefined_ownership_flags": ["specific ownership gaps with relevant text"],
  "non_testable_requirements": ["specific requirements that cannot be verified"],
  "dependency_gaps": ["specific implied dependencies not stated"],
  "scope_boundary_gaps": ["specific missing scope boundaries"],
  "contradictions_detected": ["specific conflicting statement pairs"],
  "assumptions_needing_validation": ["specific unvalidated premises"],
  "recommended_clarifications": ["specific actionable items tied to named problems"],
  "recommended_next_step": "single sentence — most important action before this spec proceeds",
  "confidence_band": "low|medium|high",
  "needs_human_review": true|false,
  "review_reason": "string if needs_human_review is true, otherwise null"
}

ANTI-HALLUCINATION RULES:
1. Every item in vague_terms_detected must appear verbatim or near-verbatim in the document
2. Do not diagnose organizational dynamics or infer why gaps exist
3. Do not pretend unknowns are known
4. Do not expand scope in recommendations beyond what is implied by the document
5. Do not summarize the document as your main behavior
6. Do not produce the corrected or improved version of the document`;

const sourceSummary = `Document has ${spec._debug_section_count} detected section(s): ${spec._debug_structural_section_list}`;

const USER_PROMPT = `Analyze the following document for ambiguity patterns.

Analysis mode: ${data.analysis_mode}
Document title: ${spec.title}
Document type: ${spec.type}
Source summary: ${sourceSummary}
Approximate word count: ${spec._debug_word_count}
Sections detected: ${spec._debug_section_count}
Preferred output tone: ${data.preferred_tone}

---

STRUCTURAL SIGNALS (pre-detected by the system before this call):

Sections found in document: ${spec._debug_structural_section_list}
Open questions already present in document: ${spec._debug_detected_open_questions}
Out-of-scope items already present in document: ${spec._debug_detected_out_of_scope_items}

Pre-detected vague terms (deterministic scan): ${spec._debug_vague_terms_found.join(', ') || 'none'}
Pre-detected ambiguity flags: ${spec._debug_deterministic_flags.map(f => f.flag_type).join(', ') || 'none'}

Use these signals as context. Do not penalize a document for problems it has already acknowledged. Do flag gaps that remain unresolved even in the presence of acknowledged questions.

---

DOCUMENT TEXT:

${spec.raw_text}

---

Produce the structured JSON diagnostic now. Every array field must be present. Return empty arrays where nothing applies. Do not omit fields.`;

let requestBody;
if (data._debug_provider_type === 'anthropic') {
  requestBody = {
    model: data._debug_model_name,
    system: SYSTEM_PROMPT,
    messages: [{ role: 'user', content: USER_PROMPT }],
    temperature: data._debug_temperature,
    max_tokens: data._debug_max_tokens
  };
} else {
  // OpenAI-compatible format (default)
  requestBody = {
    model: data._debug_model_name,
    messages: [
      { role: 'system', content: SYSTEM_PROMPT },
      { role: 'user', content: USER_PROMPT }
    ],
    temperature: data._debug_temperature,
    max_tokens: data._debug_max_tokens,
    response_format: { type: 'json_object' }
  };
}

return {
  ...data,
  _debug_ai_request_body: requestBody,
  _debug_current_spec: spec,
  _debug_prompt_prep_complete: true
};

// Parse Spec Analysis
// Extracts and validates the AI response.
// Handles both OpenAI-style and Anthropic-style response shapes.
// Gracefully handles malformed output.

const aiResponse = $input.item.json;
const previousData = $('Prep Spec Analysis Request').item.json;

const REQUIRED_FIELDS = [
  'ambiguity_summary', 'ambiguity_categories', 'severity_level',
  'highest_risk_sections', 'vague_terms_detected', 'missing_decisions',
  'undefined_ownership_flags', 'non_testable_requirements', 'dependency_gaps',
  'scope_boundary_gaps', 'contradictions_detected', 'assumptions_needing_validation',
  'recommended_clarifications', 'recommended_next_step', 'confidence_band',
  'needs_human_review', 'review_reason'
];

const VALID_SEVERITY = ['none', 'low', 'medium', 'high', 'critical'];
const VALID_CONFIDENCE = ['low', 'medium', 'high'];
const VALID_CATEGORIES = [
  'vague_language', 'missing_acceptance_criteria', 'undefined_ownership',
  'missing_decision_point', 'scope_boundary_gap', 'dependency_blind_spot',
  'untestable_requirement', 'contradictory_requirement', 'assumption_without_validation',
  'low_signal_noise'
];

function extractContentString(response) {
  // OpenAI-style
  if (response.choices && response.choices[0] && response.choices[0].message) {
    return response.choices[0].message.content;
  }
  // Anthropic-style
  if (response.content && Array.isArray(response.content) && response.content[0]) {
    return response.content[0].text;
  }
  // Direct content string
  if (typeof response === 'string') {
    return response;
  }
  return null;
}

function buildFallbackDiagnostic(reason) {
  return {
    ambiguity_summary: 'Automated analysis could not be completed. ' + reason + ' Manual review of the specification is required.',
    ambiguity_categories: [],
    severity_level: 'medium',
    highest_risk_sections: [],
    vague_terms_detected: previousData._debug_current_spec._debug_vague_terms_found || [],
    missing_decisions: [],
    undefined_ownership_flags: [],
    non_testable_requirements: [],
    dependency_gaps: [],
    scope_boundary_gaps: [],
    contradictions_detected: [],
    assumptions_needing_validation: [],
    recommended_clarifications: ['Review this specification manually — automated analysis encountered an error during processing.'],
    recommended_next_step: 'Have a human reviewer analyze this specification before it proceeds to engineering.',
    confidence_band: 'low',
    needs_human_review: true,
    review_reason: reason
  };
}

const contentString = extractContentString(aiResponse);

if (!contentString) {
  return {
    ...previousData,
    _debug_parse_failed: true,
    _debug_parse_error: 'Could not extract content string from AI response',
    _debug_raw_ai_response: JSON.stringify(aiResponse).substring(0, 500),
    parsed_analysis: buildFallbackDiagnostic('Model returned an unrecognizable response format.')
  };
}

let parsed;
try {
  // Strip markdown code fences if present
  const cleaned = contentString.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return {
    ...previousData,
    _debug_parse_failed: true,
    _debug_parse_error: 'JSON.parse failed: ' + e.message,
    _debug_raw_content_string: contentString.substring(0, 500),
    parsed_analysis: buildFallbackDiagnostic('Model output could not be parsed as valid JSON.')
  };
}

// Validate required fields
const missingFields = REQUIRED_FIELDS.filter(f => !(f in parsed));
if (missingFields.length > 0) {
  // Patch missing fields with safe defaults
  missingFields.forEach(field => {
    if (field === 'needs_human_review') parsed[field] = true;
    else if (field === 'review_reason') parsed[field] = 'Model output was missing required fields: ' + missingFields.join(', ');
    else if (Array.isArray(parsed[field])) parsed[field] = [];
    else parsed[field] = '';
  });
  parsed._debug_had_missing_fields = true;
  parsed.needs_human_review = true;
  parsed.review_reason = `Model output was missing required fields: ${missingFields.join(', ')}`;
}

// Validate enum values
if (!VALID_SEVERITY.includes(parsed.severity_level)) {
  parsed.severity_level = 'medium';
  parsed._debug_severity_corrected = true;
}
if (!VALID_CONFIDENCE.includes(parsed.confidence_band)) {
  parsed.confidence_band = 'low';
  parsed._debug_confidence_corrected = true;
}

// Filter categories to allowed list only
if (Array.isArray(parsed.ambiguity_categories)) {
  parsed.ambiguity_categories = parsed.ambiguity_categories.filter(c => VALID_CATEGORIES.includes(c));
}

return {
  ...previousData,
  _debug_parse_failed: false,
  _debug_parse_error: null,
  parsed_analysis: parsed
};

// Deterministic Quality Checks
// Post-processes the parsed AI output with deterministic rules.
// Catches cases where AI output is valid JSON but has quality problems.
// Also applies severity escalation based on deterministic evidence.

const data = $input.item.json;
const analysis = data.parsed_analysis;
const spec = data._debug_current_spec;

const deterministicFlags = spec._debug_deterministic_flags || [];
const vagueTermsFound = spec._debug_vague_terms_found || [];
const deterministicFlagCount = deterministicFlags.length;
const deterministicCategories = [...new Set(deterministicFlags.map(f => f.flag_type))];

// Cross-check: verify vague_terms_detected against deterministic findings
// Remove any AI-claimed vague terms that were NOT found deterministically
// (prevents AI from hallucinating terms that don't exist in the document)
if (Array.isArray(analysis.vague_terms_detected) && vagueTermsFound.length > 0) {
  const lowerDoc = spec.raw_text.toLowerCase();
  analysis.vague_terms_detected = analysis.vague_terms_detected.filter(term => 
    lowerDoc.includes(term.toLowerCase()) || vagueTermsFound.includes(term.toLowerCase())
  );
}

// Merge deterministic categories with AI-identified categories
const aiCategories = new Set(analysis.ambiguity_categories || []);
for (const cat of deterministicCategories) {
  if (!aiCategories.has(cat)) {
    // Add deterministically-detected category with medium confidence if missing from AI output
    const flag = deterministicFlags.find(f => f.flag_type === cat);
    if (flag && flag.confidence !== 'low') {
      aiCategories.add(cat);
    }
  }
}
analysis.ambiguity_categories = [...aiCategories];

// Severity escalation rules
let severity = analysis.severity_level || 'medium';
const SEVERITY_ORDER = ['none', 'low', 'medium', 'high', 'critical'];

function escalateSeverity(current, target) {
  const currentIdx = SEVERITY_ORDER.indexOf(current);
  const targetIdx = SEVERITY_ORDER.indexOf(target);
  return targetIdx > currentIdx ? target : current;
}

// Rule: contradictory_requirement always means at least high
if (analysis.ambiguity_categories.includes('contradictory_requirement')) {
  severity = escalateSeverity(severity, 'high');
  analysis.needs_human_review = true;
  analysis.review_reason = analysis.review_reason || 'Contradictory requirements detected — cannot be resolved through automated analysis. Human judgment required.';
}

// Rule: critical severity always requires human review
if (severity === 'critical') {
  analysis.needs_human_review = true;
  analysis.review_reason = analysis.review_reason || 'Severity is critical — human review required before this spec proceeds.';
}

// Rule: if deterministic flags significantly exceed AI-identified categories, flag for review
const aiCategoryCount = analysis.ambiguity_categories.length;
if (deterministicFlagCount > aiCategoryCount + 3) {
  analysis.needs_human_review = true;
  analysis.review_reason = analysis.review_reason || `Deterministic checks found ${deterministicFlagCount} flag(s) but AI identified only ${aiCategoryCount} category(ies) — potential underdiagnosis. Human review recommended.`;
}

// Rule: if recommended_clarifications is empty but categories are non-empty, flag the inconsistency
if (analysis.ambiguity_categories.length > 0 && 
    (!analysis.recommended_clarifications || analysis.recommended_clarifications.length === 0)) {
  analysis.recommended_clarifications = ['Review each flagged ambiguity category and request specific clarification from the spec author before proceeding.'];
  analysis._debug_clarifications_patched = true;
}

// Rule: if contradictions detected array is empty but contradictory_requirement is a category
if (analysis.ambiguity_categories.includes('contradictory_requirement') && 
    (!analysis.contradictions_detected || analysis.contradictions_detected.length === 0)) {
  analysis.contradictions_detected = ['Contradiction detected by structural analysis — review document for conflicting scope or requirement statements.'];
}

analysis.severity_level = severity;

// Validate confidence_band given document quality
if (spec._debug_word_count < 300 && analysis.confidence_band === 'high') {
  analysis.confidence_band = 'medium';
  analysis._debug_confidence_downgraded = true;
  analysis.needs_human_review = true;
  analysis.review_reason = analysis.review_reason || 'Document is borderline signal — confidence downgraded from high to medium for short documents under 300 words.';
}

// Add deterministic vague terms if AI missed them
if (vagueTermsFound.length > 0) {
  const existing = new Set((analysis.vague_terms_detected || []).map(t => t.toLowerCase()));
  for (const term of vagueTermsFound) {
    if (!existing.has(term.toLowerCase())) {
      analysis.vague_terms_detected = analysis.vague_terms_detected || [];
      analysis.vague_terms_detected.push(term);
    }
  }
}

return {
  ...data,
  parsed_analysis: analysis,
  _debug_quality_checks_complete: true,
  _debug_post_check_severity: severity,
  _debug_final_category_count: analysis.ambiguity_categories.length
};

// Prep Portfolio Review
// Collects individual spec analyses and constructs the portfolio-level prompt.
// Aggregates analysis results, identifies cross-doc patterns, builds prompt context.

const data = $input.item.json;
const allSpecs = data.normalized_specs || [];
const primaryAnalysis = data.parsed_analysis;

// In single-pass portfolio mode, primary analysis is the first spec
// Additional specs would be analyzed in parallel and collected here
// For this implementation, we use the primary analysis plus spec metadata from all specs
const specAnalyses = [
  {
    title: data._debug_current_spec.title,
    type: data._debug_current_spec.type,
    word_count: data._debug_current_spec._debug_word_count,
    analysis: primaryAnalysis
  }
];

// Add summaries for other specs if available (multi-spec portfolio input)
if (allSpecs.length > 1) {
  for (let i = 1; i < allSpecs.length; i++) {
    const spec = allSpecs[i];
    specAnalyses.push({
      title: spec.title,
      type: spec.type,
      word_count: spec._debug_word_count,
      analysis: {
        ambiguity_summary: 'Not individually analyzed in this run — see raw text for manual review.',
        ambiguity_categories: spec._debug_deterministic_flags.map(f => f.flag_type),
        severity_level: spec._debug_pre_severity_estimate,
        vague_terms_detected: spec._debug_vague_terms_found,
        needs_human_review: spec._debug_flag_count > 3,
        confidence_band: 'low'
      }
    });
  }
}

const specCount = specAnalyses.length;
const highRiskCount = specAnalyses.filter(s => ['high', 'critical'].includes(s.analysis.severity_level)).length;
const needsReviewCount = specAnalyses.filter(s => s.analysis.needs_human_review).length;

// Find categories appearing in multiple specs
const categoryCounts = {};
for (const s of specAnalyses) {
  for (const cat of (s.analysis.ambiguity_categories || [])) {
    categoryCounts[cat] = (categoryCounts[cat] || 0) + 1;
  }
}
const repeatedCategories = Object.entries(categoryCounts)
  .filter(([, count]) => count >= 2)
  .map(([cat]) => cat);

const dateRange = data.time_window_start && data.time_window_end
  ? `${data.time_window_start} to ${data.time_window_end}`
  : 'not specified';

const PORTFOLIO_SYSTEM_PROMPT = `You are a requirements-quality analyst conducting a cross-document portfolio review. You have received the individual ambiguity diagnostic results for two or more specification documents. Your task is to identify recurring patterns, systemic gaps, and delivery risk that spans the set.

You are not re-analyzing individual specs. Identify what they have in common, where risk is concentrated, and what portfolio-level actions the team should take.

Focus on:
1. Recurring ambiguity categories appearing in multiple specs
2. Common ownership gaps — same functions consistently unowned
3. Common missing decisions — same types of decisions consistently deferred
4. Weak scope discipline — missing out-of-scope sections across the set
5. Specs at highest delivery risk
6. Specs requiring rewrite rather than targeted clarification

Respond with a single valid JSON object. No markdown. No code fences. No prose before or after the JSON.

Required fields:
{
  "review_summary": "3-6 sentences on overall quality and portfolio-level delivery risk",
  "top_risk_specs": [{"title": "exact title", "risk_reason": "one sentence"}],
  "repeated_ambiguity_categories": [{"category": "string", "occurrence_count": 0, "pattern_description": "one sentence"}],
  "common_decision_gaps": ["types of decisions consistently deferred"],
  "common_ownership_gaps": ["types of ownership consistently undefined"],
  "common_acceptance_criteria_failures": ["types of requirements consistently lacking criteria"],
  "specs_needing_rewrite": [{"title": "exact title", "reason": "one sentence"}],
  "portfolio_recommendations": ["portfolio-level actions — not spec-by-spec fixes"],
  "confidence_band": "low|medium|high",
  "needs_human_review": true|false,
  "review_reason": "string or null"
}`;

const PORTFOLIO_USER_PROMPT = `Conduct a portfolio-level review of the following spec analyses.

Portfolio size: ${specCount} spec(s)
Date range: ${dateRange}
Preferred output tone: ${data.preferred_tone}
Specs with high or critical severity: ${highRiskCount}
Specs flagged for human review: ${needsReviewCount}
Categories appearing in multiple specs: ${repeatedCategories.join(', ') || 'none identified'}

---

INDIVIDUAL SPEC DIAGNOSTIC RESULTS:

${JSON.stringify(specAnalyses, null, 2)}

---

Identify cross-document patterns. Only name a pattern as recurring if it appears in at least 2 specs. Produce portfolio-level recommendations — not spec-by-spec fixes.`;

let portfolioRequestBody;
if (data._debug_provider_type === 'anthropic') {
  portfolioRequestBody = {
    model: data._debug_model_name,
    system: PORTFOLIO_SYSTEM_PROMPT,
    messages: [{ role: 'user', content: PORTFOLIO_USER_PROMPT }],
    temperature: data._debug_temperature,
    max_tokens: 3000
  };
} else {
  portfolioRequestBody = {
    model: data._debug_model_name,
    messages: [
      { role: 'system', content: PORTFOLIO_SYSTEM_PROMPT },
      { role: 'user', content: PORTFOLIO_USER_PROMPT }
    ],
    temperature: data._debug_temperature,
    max_tokens: 3000,
    response_format: { type: 'json_object' }
  };
}

return {
  ...data,
  _debug_portfolio_request_body: portfolioRequestBody,
  _debug_portfolio_spec_count: specCount,
  _debug_portfolio_high_risk_count: highRiskCount,
  _debug_portfolio_repeated_categories: repeatedCategories,
  _debug_portfolio_prep_complete: true
};

// Parse Portfolio Review
// Extracts and validates the portfolio AI response.
// Same fallback logic as the single-spec parse node.

const aiResponse = $input.item.json;
const previousData = $('Prep Portfolio Review').item.json;

const REQUIRED_PORTFOLIO_FIELDS = [
  'review_summary', 'top_risk_specs', 'repeated_ambiguity_categories',
  'common_decision_gaps', 'common_ownership_gaps', 'common_acceptance_criteria_failures',
  'specs_needing_rewrite', 'portfolio_recommendations', 'confidence_band',
  'needs_human_review', 'review_reason'
];

function extractContentString(response) {
  if (response.choices && response.choices[0] && response.choices[0].message) {
    return response.choices[0].message.content;
  }
  if (response.content && Array.isArray(response.content) && response.content[0]) {
    return response.content[0].text;
  }
  if (typeof response === 'string') return response;
  return null;
}

function buildFallbackPortfolio(reason) {
  return {
    review_summary: 'Portfolio review could not be completed. ' + reason + ' Manual review of the spec set is required.',
    top_risk_specs: [],
    repeated_ambiguity_categories: [],
    common_decision_gaps: [],
    common_ownership_gaps: [],
    common_acceptance_criteria_failures: [],
    specs_needing_rewrite: [],
    portfolio_recommendations: ['Conduct manual portfolio review — automated analysis encountered an error during processing.'],
    confidence_band: 'low',
    needs_human_review: true,
    review_reason: reason
  };
}

const contentString = extractContentString(aiResponse);

if (!contentString) {
  return {
    ...previousData,
    _debug_portfolio_parse_failed: true,
    portfolio_analysis: buildFallbackPortfolio('Model returned an unrecognizable response format for portfolio review.')
  };
}

let parsed;
try {
  const cleaned = contentString.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return {
    ...previousData,
    _debug_portfolio_parse_failed: true,
    portfolio_analysis: buildFallbackPortfolio('Portfolio review model output could not be parsed as valid JSON.')
  };
}

// Patch missing fields
const missingFields = REQUIRED_PORTFOLIO_FIELDS.filter(f => !(f in parsed));
if (missingFields.length > 0) {
  missingFields.forEach(field => {
    if (field === 'needs_human_review') parsed[field] = true;
    else if (field === 'review_reason') parsed[field] = 'Missing fields: ' + missingFields.join(', ');
    else if (['top_risk_specs', 'repeated_ambiguity_categories', 'specs_needing_rewrite'].includes(field)) parsed[field] = [];
    else if (Array.isArray(parsed[field])) parsed[field] = [];
    else parsed[field] = '';
  });
  parsed.needs_human_review = true;
}

// Validate confidence below minimum portfolio spec count
if (previousData._debug_portfolio_spec_count < 3) {
  parsed.confidence_band = 'low';
  parsed.needs_human_review = true;
  parsed.review_reason = parsed.review_reason || `Portfolio review received only ${previousData._debug_portfolio_spec_count} spec(s). Minimum for reliable cross-document analysis is 3.`;
}

return {
  ...previousData,
  _debug_portfolio_parse_failed: false,
  portfolio_analysis: parsed
};

// Final Response
// Constructs the clean, public-facing response by stripping all _debug_ fields.
// Structures the final JSON from validated, cleaned fields.
// Adds generated_at timestamp and analysis_mode for caller context.

const data = $input.item.json;

function stripDebugFields(obj) {
  if (typeof obj !== 'object' || obj === null) return obj;
  if (Array.isArray(obj)) return obj.map(stripDebugFields);
  const cleaned = {};
  for (const [key, value] of Object.entries(obj)) {
    if (!key.startsWith('_debug_')) {
      cleaned[key] = stripDebugFields(value);
    }
  }
  return cleaned;
}

const isPortfolio = data.analysis_mode === 'portfolio_review' && data.portfolio_analysis;

let responsePayload;

if (isPortfolio) {
  // Portfolio mode: return portfolio analysis as primary response
  const cleanPortfolio = stripDebugFields(data.portfolio_analysis);
  responsePayload = {
    analysis_mode: 'portfolio_review',
    generated_at: new Date().toISOString(),
    spec_count: data._debug_portfolio_spec_count || 1,
    ...cleanPortfolio
  };
} else {
  // Single spec mode: return individual analysis
  const cleanAnalysis = stripDebugFields(data.parsed_analysis);
  responsePayload = {
    analysis_mode: data.analysis_mode || 'single_spec',
    generated_at: new Date().toISOString(),
    ...cleanAnalysis
  };
}

return responsePayload;
